function FilterChip({ label, active, count, onClick }) {
  return (
    <button
      type="button"
      className={`opp-filter-chip${active ? ' opp-filter-chip--active' : ''}`}
      onClick={onClick}
    >
      {label}
      {count > 0 && <span className="opp-filter-chip-count">{count}</span>}
    </button>
  );
}

function OpportunityCard({ opp, saved, onToggleSave, onInquire }) {
  return (
    <RevealOnScroll className="opp-card-wrapper">
      <article className="opp-card">
        <div className="opp-card-header">
          <span className="opp-card-agency">{opp.agency}</span>
          <div className="opp-card-actions">
            <button
              type="button"
              className={`opp-icon-btn${saved ? ' opp-icon-btn--saved' : ''}`}
              onClick={() => onToggleSave(opp.id)}
              aria-label={saved ? 'Remove from saved' : 'Save opportunity'}
            >
              <Heart weight={saved ? 'fill' : 'regular'} size={18} />
            </button>
          </div>
        </div>

        <h3 className="opp-card-title">{opp.title}</h3>

        {opp.description && (
          <p className="opp-card-desc">{opp.description}</p>
        )}

        <div className="opp-card-meta">
          {opp.location && (
            <span className="opp-card-tag">
              <MapPin size={14} weight="bold" /> {opp.location}
            </span>
          )}
          {opp.role_type && (
            <span className="opp-card-tag">
              <Briefcase size={14} weight="bold" /> {opp.role_type}
            </span>
          )}
          {opp.term_length && (
            <span className="opp-card-tag">
              <Clock size={14} weight="bold" /> {opp.term_length}
            </span>
          )}
        </div>

        <div className="opp-card-footer">
          <a href={opp.url} target="_blank" rel="noreferrer" className="opp-card-link">
            View details &rarr;
          </a>
          <button
            type="button"
            className="opp-inquire-btn"
            onClick={() => onInquire(opp)}
          >
            <EnvelopeSimple size={16} weight="bold" /> Inquire
          </button>
        </div>
      </article>
    </RevealOnScroll>
  );
}

function InquiryModal({ opportunity, onClose }) {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [message, setMessage] = useState('');
  const [sent, setSent] = useState(false);

  if (!opportunity) return null;

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (supabase) {
      await supabase.from('inquiries').insert({
        opportunity_id: opportunity.id,
        name,
        email,
        message,
        agency: opportunity.agency,
        opportunity_title: opportunity.title
      });
    }
    setSent(true);
  };

  return (
    <div className="opp-modal-overlay" role="presentation" onClick={onClose} onKeyDown={(e) => { if (e.key === 'Escape') onClose(); }}>
      {/* eslint-disable-next-line jsx-a11y/no-noninteractive-element-interactions, jsx-a11y/click-events-have-key-events */}
      <div className="opp-modal" role="dialog" aria-label="Send inquiry" onClick={(e) => e.stopPropagation()}>
        <button type="button" className="opp-modal-close" onClick={onClose} aria-label="Close">
          <X size={20} />
        </button>

        {sent ? (
          <div className="opp-modal-success">
            <h3>Inquiry sent</h3>
            <p>Your interest in <strong>{opportunity.title}</strong> at {opportunity.agency} has been noted. Check your email for next steps.</p>
            <button type="button" className="cta-button" onClick={onClose}>Close</button>
          </div>
        ) : (
          <>
            <h3>Inquire about this opportunity</h3>
            <p className="opp-modal-subtitle">
              <strong>{opportunity.title}</strong> &mdash; {opportunity.agency}
            </p>
            <form onSubmit={handleSubmit} className="opp-inquiry-form">
              <label>
                Name
                <input type="text" value={name} onChange={(e) => setName(e.target.value)} required />
              </label>
              <label>
                Email
                <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} required />
              </label>
              <label>
                Message
                <textarea
                  value={message}
                  onChange={(e) => setMessage(e.target.value)}
                  rows={4}
                  placeholder="Tell them a bit about yourself and why this opportunity interests you..."
                />
              </label>
              <button type="submit" className="cta-button">Send inquiry</button>
            </form>
          </>
        )}
      </div>
    </div>
  );
}

export default function OpportunitiesExplorer({ agencyFilter }) {
  const [opportunities, setOpportunities] = useState(BAKED_OPPORTUNITIES);
  const [loading, setLoading] = useState(false);
  const [loadError, setLoadError] = useState(false);

  // Filters — Sets for multi-select (union/OR within a category, intersection/AND across categories)
  const [search, setSearch] = useState('');
  const [selectedAgencies, setSelectedAgencies] = useState(() =>
    agencyFilter ? new Set([agencyFilter]) : new Set()
  );
  const [selectedRegions, setSelectedRegions] = useState(new Set());
  const [selectedRoles, setSelectedRoles] = useState(new Set());
  const [selectedTerms, setSelectedTerms] = useState(new Set());
  const [showFilters, setShowFilters] = useState(false);

  function toggleFilter(setter, value) {
    setter(prev => {
      const next = new Set(prev);
      if (next.has(value)) next.delete(value);
      else next.add(value);
      return next;
    });
  }

  // Saved + inquiry
  const [savedIds, setSavedIds] = useState(() => {
    try {
      return new Set(JSON.parse(localStorage.getItem('fielded_saved_opps') || '[]'));
    } catch { return new Set(); }
  });
  const [showSavedOnly, setShowSavedOnly] = useState(false);
  const [inquiryOpp, setInquiryOpp] = useState(null);

  useEffect(() => {
    if (!supabase) return;
    let cancelled = false;
    async function refresh() {
      setLoading(true);
      setLoadError(false);
      const allRows = [];
      const PAGE_SIZE = 1000;
      let from = 0;
      try {
        while (true) {
          const { data, error } = await supabase
            .from('opportunities')
            .select('id, agency, title, url, location, region, role_type, term_length, description')
            .eq('active', true)
            .order('agency', { ascending: true })
            .order('title', { ascending: true })
            .range(from, from + PAGE_SIZE - 1);
          if (cancelled) return;
          if (error) throw error;
          allRows.push(...(data || []));
          if (!data || data.length < PAGE_SIZE) break;
          from += PAGE_SIZE;
        }
        if (!cancelled && allRows.length > 0) {
          setOpportunities(allRows);
        }
      } catch (err) {
        if (cancelled) return;
        // Network hiccup or RLS misconfig — keep showing the baked-in
        // snapshot (already the initial state) rather than an empty list,
        // but surface it so a stale-data banner can render and so this
        // shows up in error monitoring instead of failing silently.
        console.error('Failed to load live opportunities, showing cached snapshot:', err);
        setLoadError(true);
      } finally {
        if (!cancelled) setLoading(false);
      }
    }
    refresh();
    return () => { cancelled = true; };
  }, []);

  useEffect(() => {
    localStorage.setItem('fielded_saved_opps', JSON.stringify([...savedIds]));
  }, [savedIds]);

  const agencies = useMemo(
    () => [...new Set(opportunities.map((o) => o.agency))].sort(),
    [opportunities]
  );

  const filtered = useMemo(() => {
    let list = opportunities;

    if (showSavedOnly) {
      list = list.filter((o) => savedIds.has(o.id));
    }
    if (search) {
      const q = search.toLowerCase();
      list = list.filter((o) =>
        o.title.toLowerCase().includes(q) ||
        (o.description || '').toLowerCase().includes(q) ||
        o.agency.toLowerCase().includes(q) ||
        (o.location || '').toLowerCase().includes(q)
      );
    }
    if (selectedAgencies.size > 0) list = list.filter((o) => selectedAgencies.has(o.agency));
    if (selectedRegions.size > 0) list = list.filter((o) => selectedRegions.has(o.region));
    if (selectedRoles.size > 0) list = list.filter((o) => selectedRoles.has(o.role_type));
    if (selectedTerms.size > 0) list = list.filter((o) => selectedTerms.has(o.term_length));

    return list;
  }, [opportunities, search, selectedAgencies, selectedRegions, selectedRoles, selectedTerms, showSavedOnly, savedIds]);

  function toggleSave(id) {
    setSavedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  function clearFilters() {
    setSearch('');
    setSelectedAgencies(new Set());
    setSelectedRegions(new Set());
    setSelectedRoles(new Set());
    setSelectedTerms(new Set());
    setShowSavedOnly(false);
  }

  const activeFilterCount = selectedAgencies.size + selectedRegions.size + selectedRoles.size + selectedTerms.size;
  const hasActiveFilters = search || activeFilterCount > 0 || showSavedOnly;

  return (
    <div className="opp-explorer">
      {/* Search + filter bar */}
      <div className="opp-toolbar">
        <div className="opp-search-wrap">
          <MagnifyingGlass size={18} className="opp-search-icon" />
          <input
            type="search"
            className="opp-search"
            placeholder="Search opportunities..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <button
          type="button"
          className={`opp-filter-toggle${showFilters ? ' opp-filter-toggle--open' : ''}`}
          onClick={() => setShowFilters(!showFilters)}
        >
          <Funnel size={16} weight="bold" />
          Filters
          {activeFilterCount > 0 && <span className="opp-filter-badge">{activeFilterCount}</span>}
          <CaretDown size={14} className={`opp-caret${showFilters ? ' opp-caret--open' : ''}`} />
        </button>
        <button
          type="button"
          className={`opp-icon-btn opp-saved-toggle${showSavedOnly ? ' opp-icon-btn--saved' : ''}`}
          onClick={() => setShowSavedOnly(!showSavedOnly)}
          aria-label={showSavedOnly ? 'Show all' : 'Show saved only'}
        >
          <Heart weight={showSavedOnly ? 'fill' : 'regular'} size={18} />
          <span className="opp-saved-count">{savedIds.size}</span>
        </button>
      </div>

      {/* Expandable filter panel */}
      {showFilters && (
        <div className="opp-filters">
          <div className="opp-filter-group">
            <span className="opp-filter-label">
              Agency
              {selectedAgencies.size > 0 && <span className="opp-filter-label-count">{selectedAgencies.size}</span>}
            </span>
            <div className="opp-chip-row">
              {agencies.map((a) => (
                <FilterChip key={a} label={a} active={selectedAgencies.has(a)}
                  onClick={() => toggleFilter(setSelectedAgencies, a)} />
              ))}
            </div>
          </div>
          <div className="opp-filter-group">
            <span className="opp-filter-label">
              Region
              {selectedRegions.size > 0 && <span className="opp-filter-label-count">{selectedRegions.size}</span>}
            </span>
            <div className="opp-chip-row">
              {REGIONS.map((r) => (
                <FilterChip key={r} label={r} active={selectedRegions.has(r)}
                  onClick={() => toggleFilter(setSelectedRegions, r)} />
              ))}
            </div>
          </div>
          <div className="opp-filter-group">
            <span className="opp-filter-label">
              Role type
              {selectedRoles.size > 0 && <span className="opp-filter-label-count">{selectedRoles.size}</span>}
            </span>
            <div className="opp-chip-row">
              {ROLE_TYPES.map((r) => (
                <FilterChip key={r} label={r} active={selectedRoles.has(r)}
                  onClick={() => toggleFilter(setSelectedRoles, r)} />
              ))}
            </div>
          </div>
          <div className="opp-filter-group">
            <span className="opp-filter-label">
              Term length
              {selectedTerms.size > 0 && <span className="opp-filter-label-count">{selectedTerms.size}</span>}
            </span>
            <div className="opp-chip-row">
              {TERM_LENGTHS.map((t) => (
                <FilterChip key={t} label={t} active={selectedTerms.has(t)}
                  onClick={() => toggleFilter(setSelectedTerms, t)} />
              ))}
            </div>
          </div>
          {hasActiveFilters && (
            <button type="button" className="opp-clear-filters" onClick={clearFilters}>
              Clear all filters {activeFilterCount > 0 && `(${activeFilterCount})`}
            </button>
          )}
        </div>
      )}

      {/* Results */}
      {loadError && (
        <p className="opp-error opp-error--inline" role="status">
          Couldn't reach live listings right now — showing a recent saved snapshot instead.
        </p>
      )}
      <div className="opp-results-header">
        <p className="opp-results-count">
          {filtered.length} {filtered.length === 1 ? 'opportunity' : 'opportunities'}
          {hasActiveFilters ? ' matching your filters' : ''}
          {loading ? ' (refreshing…)' : ''}
        </p>
      </div>

      {filtered.length === 0 ? (
        <div className="opp-empty">
          <p>No opportunities match your current filters.</p>
          {hasActiveFilters && (
            <button type="button" className="cta-button" onClick={clearFilters}>
              Clear filters
            </button>
          )}
        </div>
      ) : (
        <div className="opp-grid">
          {filtered.map((opp) => (
            <OpportunityCard
              key={opp.id}
              opp={opp}
              saved={savedIds.has(opp.id)}
              onToggleSave={toggleSave}
              onInquire={setInquiryOpp}
            />
          ))}
        </div>
      )}

      <InquiryModal opportunity={inquiryOpp} onClose={() => setInquiryOpp(null)} />
    </div>
  );
}
